insert into public.messages (id, trip_id, sender_member_id, guest_name, body, thread_date, is_announcement, is_deleted) values ('b93e72a2-f0a5-542f-86f9-8f82e3e7760d', '0039b7b6-fa06-5288-8ab8-bd612320d7f5', 'a1b2c3d4-0001-0001-0001-000000000001', null, 'Just locked in tee times for Pebble and Spyglass — you''re going to want to pack rain gear just in case. Weather looks mostly clear but coastal fog is always possible. Bag drop opens at 6:30 AM on Thursday.', '2025-05-20', false, false) on conflict (id) do nothing;
insert into public.messages (id, trip_id, sender_member_id, guest_name, body, thread_date, is_announcement, is_deleted) values ('0a5aeb67-12c7-5e70-88f4-42478256b72b', '0039b7b6-fa06-5288-8ab8-bd612320d7f5', 'a1b2c3d4-0001-0001-0001-000000000001', null, '🏌️ REMINDER: Balances are due by June 1st. Check the Expenses tab — each of you owes $1,645. Venmo links are ready to go. Let''s get settled up before we tee off!', '2025-05-28', true, false) on conflict (id) do nothing;
insert into public.messages (id, trip_id, sender_member_id, guest_name, body, thread_date, is_announcement, is_deleted) values ('bf2050cb-5ad0-5417-8efc-9a52de9005cd', '4f4515a7-0310-5671-8e41-3201c05139bb', 'a1b2c3d4-0002-0002-0002-000000000002', null, 'That back nine at TPC was something else. Ryan nearly holed out on 16 — absolute chaos. Final scores are posted in the Rounds tab. Same crew next year?', '2025-03-09', false, false) on conflict (id) do nothing;
insert into public.messages (id, trip_id, sender_member_id, guest_name, body, thread_date, is_announcement, is_deleted) values ('05dd9266-eedd-5d95-8a8c-d2c59200168a', '4f303bf4-e22e-5559-870f-25e00bb08ae3', 'a1b2c3d4-0003-0003-0003-000000000003', null, 'Bandon confirmed for September! We have walking-only tee times on Thursday and Friday. I''m requesting caddies for all four of us — highly recommend it for the links-style terrain. Start thinking about which courses you want on Saturday and Sunday.', '2025-02-14', false, false) on conflict (id) do nothing;
insert into public.announcements (id, trip_id, message_id, body, created_by, is_active) values ('ed0cf7f2-6b06-5a49-897d-aa51bcd09665', '0039b7b6-fa06-5288-8ab8-bd612320d7f5', '0a5aeb67-12c7-5e70-88f4-42478256b72b', '🏌️ REMINDER: Balances are due by June 1st. Check the Expenses tab — each of you owes $1,645. Venmo links are ready to go. Let''s get settled up before we tee off!', 'a1b2c3d4-0001-0001-0001-000000000001', true) on conflict (id) do nothing;
insert into public.announcements (id, trip_id, body, created_by, is_active) values ('0e5bbe3e-39df-5a6e-8729-bd41ec00c2e0', '4f303bf4-e22e-5559-870f-25e00bb08ae3', '📋 Bandon Dunes Trip is in planning mode — please confirm your attendance by August 1st so we can finalize tee times and lodging. Caddie deposit ($200/person) will be collected via the Expenses tab once headcount is locked.', 'a1b2c3d4-0003-0003-0003-000000000003', true) on conflict (id) do nothing;
